document.addEventListener("DOMContentLoaded",()=>{const form=document.getElementById("subscriptionForm");const nameInput=document.getElementById("name");const emailInput=document.getElementById("email");const nameError=document.getElementById("nameError");const emailError=document.getElementById("emailError");const successMessage=document.getElementById("successMessage");function validateName(name){return/^[A-Za-zÁÉÍÓÚáéíóúÑñ ]{10,50}$/.test(name)}
function validateEmail(email){return/^[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$/i.test(email)&&email.length>=8&&!email.endsWith(".")}
form.addEventListener("submit",(e)=>{e.preventDefault();const nameValue=nameInput.value.trim();const emailValue=emailInput.value.trim();let isValid=!0;nameError.textContent="";emailError.textContent="";successMessage.textContent="";if(!validateName(nameValue)){nameError.textContent="El nombre debe tener entre 10 y 50 caracteres sin números.";isValid=!1}
if(!validateEmail(emailValue)){emailError.textContent="Correo inválido. Verifica el formato.";isValid=!1}
if(isValid){successMessage.innerHTML=`
                Gracias por suscribirte.<br>
                Nombre: ${nameValue}<br>
                Correo: ${emailValue}<br>
                En breve nos comunicaremos contigo.
            `;form.reset()}});nameInput.addEventListener("input",()=>{if(validateName(nameInput.value.trim())){nameError.textContent=""}});emailInput.addEventListener("input",()=>{if(validateEmail(emailInput.value.trim())){emailError.textContent=""}})})